import { useState, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import axios from "axios";
import {
  ArrowLeft,
  MapPin,
  Clock,
  Mountain,
  TrendingUp,
  Loader2,
  Camera,
  Calendar,
  Route,
  Timer,
  Download,
  Home,
  Users,
  Phone,
  ChevronRight,
} from "lucide-react";
import { motion } from "framer-motion";
import { Header } from "../components/Header";
import { Footer } from "../components/Footer";
import { useLogoutHandler } from "../hooks/useLogoutHandler";
import LogoutModal from "../components/LogoutModal";

const API = "http://localhost:5000";

const difficultyColors = {
  Easy: "bg-emerald-100 text-emerald-700 border-emerald-200",
  Moderate: "bg-amber-100 text-amber-700 border-amber-200",
  Difficult: "bg-orange-100 text-orange-700 border-orange-200",
  Extreme: "bg-red-100 text-red-700 border-red-200",
};

const difficultyDot = {
  Easy: "bg-emerald-500",
  Moderate: "bg-amber-500",
  Difficult: "bg-orange-500",
  Extreme: "bg-red-500",
};

/* ──────────────────────────────────────────────
   PHOTO GALLERY — Professional Mosaic Layout
────────────────────────────────────────────── */
const PhotoGallery = ({ images }) => {
  const [lightbox, setLightbox] = useState(null);

  if (!images?.length) return null;

  const count = Math.min(images.length, 5);
  const visible = images.slice(0, count);
  const imgSrc = (img) => `${API}${img.image_path}`;

  const open = (img) => setLightbox(images.indexOf(img));

  let grid = null;

  if (count === 1) {
    grid = (
      <div
        className="h-80 rounded-2xl overflow-hidden shadow-lg group cursor-zoom-in"
        onClick={() => open(visible[0])}
      >
        <img src={imgSrc(visible[0])} alt="Trail" className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-[1.04]" />
      </div>
    );
  } else if (count === 2) {
    grid = (
      <div className="grid grid-cols-2 gap-2.5 h-72 rounded-2xl overflow-hidden shadow-lg">
        {visible.map((img) => (
          <div key={img.image_id} className="overflow-hidden group cursor-zoom-in" onClick={() => open(img)}>
            <img src={imgSrc(img)} alt="Trail" className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-[1.06]" />
          </div>
        ))}
      </div>
    );
  } else if (count === 3) {
    grid = (
      <div className="grid grid-cols-2 gap-2.5 rounded-2xl overflow-hidden shadow-lg" style={{ height: "340px" }}>
        <div className="overflow-hidden group cursor-zoom-in row-span-2" onClick={() => open(visible[0])}>
          <img src={imgSrc(visible[0])} alt="Trail" className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-[1.05]" />
        </div>
        {visible.slice(1).map((img) => (
          <div key={img.image_id} className="overflow-hidden group cursor-zoom-in" onClick={() => open(img)}>
            <img src={imgSrc(img)} alt="Trail" className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-[1.07]" />
          </div>
        ))}
      </div>
    );
  } else if (count === 4) {
    grid = (
      <div className="grid grid-cols-2 gap-2.5 rounded-2xl overflow-hidden shadow-lg">
        {visible.map((img) => (
          <div key={img.image_id} className="aspect-video overflow-hidden group cursor-zoom-in" onClick={() => open(img)}>
            <img src={imgSrc(img)} alt="Trail" className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-[1.06]" />
          </div>
        ))}
      </div>
    );
  } else {
    /* 5 images — flex layout: big left (60%) + 2×2 right (40%) */
    grid = (
      <div className="flex gap-2.5 rounded-2xl overflow-hidden shadow-xl" style={{ height: "460px" }}>
        {/* Large left tile */}
        <div
          className="flex-[3] relative overflow-hidden group cursor-zoom-in"
          onClick={() => open(visible[0])}
        >
          <img
            src={imgSrc(visible[0])}
            alt="Trail"
            className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-[1.04]"
          />
        </div>
        {/* Right 2×2 grid */}
        <div className="flex-[2] grid grid-cols-2 grid-rows-2 gap-2.5">
          {visible.slice(1).map((img) => (
            <div
              key={img.image_id}
              className="overflow-hidden group cursor-zoom-in"
              onClick={() => open(img)}
            >
              <img
                src={imgSrc(img)}
                alt="Trail"
                className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-[1.08]"
              />
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <>
      {grid}

      {/* Lightbox */}
      {lightbox !== null && (
        <div
          className="fixed inset-0 z-50 bg-black/92 flex items-center justify-center p-4"
          onClick={() => setLightbox(null)}
        >
          <button
            className="absolute top-5 right-5 w-9 h-9 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 text-white text-xl transition"
            onClick={() => setLightbox(null)}
          >
            ×
          </button>
          <button
            className="absolute left-4 top-1/2 -translate-y-1/2 w-10 h-10 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 text-white text-2xl transition"
            onClick={(e) => { e.stopPropagation(); setLightbox((i) => (i - 1 + images.length) % images.length); }}
          >
            ‹
          </button>
          <button
            className="absolute right-4 top-1/2 -translate-y-1/2 w-10 h-10 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 text-white text-2xl transition"
            onClick={(e) => { e.stopPropagation(); setLightbox((i) => (i + 1) % images.length); }}
          >
            ›
          </button>
          <img
            src={`${API}${images[lightbox]?.image_path}`}
            alt="Trail"
            className="max-h-[88vh] max-w-[88vw] rounded-2xl object-contain shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          />
          <p className="absolute bottom-5 left-1/2 -translate-x-1/2 text-white/50 text-xs tracking-widest">
            {lightbox + 1} / {images.length}
          </p>
        </div>
      )}
    </>
  );
};

/* ──────────────────────────────────────────────
   HOMESTAY CARD
────────────────────────────────────────────── */
const HomestayCard = ({ homestay }) => {
  const primaryImage = homestay.images?.find((i) => i.is_primary) || homestay.images?.[0];

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      className="bg-white rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow overflow-hidden flex flex-col"
    >
      {/* Image */}
      <div className="h-44 bg-gray-100 overflow-hidden flex-shrink-0">
        {primaryImage ? (
          <img
            src={`${API}${primaryImage.image_path}`}
            alt={homestay.name}
            className="w-full h-full object-cover transition-transform duration-500 hover:scale-105"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <Home className="h-10 w-10 text-gray-200" />
          </div>
        )}
      </div>

      {/* Content */}
      <div className="p-4 flex flex-col flex-1">
        <h4 className="font-bold text-charcoal text-base leading-snug mb-1">{homestay.name}</h4>

        <div className="flex items-center gap-1.5 text-sm text-gray-400 mb-3">
          <MapPin className="h-3.5 w-3.5 flex-shrink-0" />
          {homestay.location}
        </div>

        {homestay.description && (
          <p className="text-gray-500 text-xs leading-relaxed mb-3 line-clamp-2">{homestay.description}</p>
        )}

        <div className="mt-auto space-y-2">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-1.5 text-xs text-gray-400">
              <Users className="h-3.5 w-3.5" />
              Up to {homestay.capacity} guest{homestay.capacity !== 1 ? "s" : ""}
            </div>
            <div className="text-right">
              <span className="text-base font-extrabold text-charcoal">NPR {Number(homestay.price_per_night).toLocaleString()}</span>
              <span className="text-xs text-gray-400"> /night</span>
            </div>
          </div>

          {homestay.contact_phone && (
            <a
              href={`tel:${homestay.contact_phone}`}
              className="w-full flex items-center justify-center gap-2 py-2.5 text-sm font-semibold rounded-xl border border-gray-200 text-gray-600 hover:border-gold hover:text-gold transition-colors"
            >
              <Phone className="h-4 w-4" />
              {homestay.contact_phone}
            </a>
          )}
        </div>
      </div>
    </motion.div>
  );
};

/* ──────────────────────────────────────────────
   SECTION HEADING (gold accent bar)
────────────────────────────────────────────── */
const SectionHeading = ({ children }) => (
  <div className="flex items-center gap-3">
    <div className="w-1 h-6 rounded-full flex-shrink-0" style={{ background: "linear-gradient(to bottom, #C8932A, #E0B04A)" }} />
    <h2 className="text-2xl font-bold text-charcoal font-heading">{children}</h2>
  </div>
);

/* ──────────────────────────────────────────────
   MAIN PAGE
────────────────────────────────────────────── */
const TrailDetail = () => {
  const { id } = useParams();
  const [trail, setTrail] = useState(null);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState(null);
  const [homestays, setHomestays] = useState([]);
  const [homestaysLoading, setHomestaysLoading] = useState(false);

  const {
    handleLogout: originalHandleLogout,
    handleStayLoggedIn,
    showLogoutModal,
    setShowLogoutModal,
  } = useLogoutHandler();

  const handleLogout = () => { originalHandleLogout(); };

  useEffect(() => {
    const token = sessionStorage.getItem("token");
    const userData = sessionStorage.getItem("user");
    if (token && userData) setUser(JSON.parse(userData));
  }, []);

  useEffect(() => {
    const fetchTrail = async () => {
      try {
        const res = await axios.get(`${API}/api/trails/public/${id}`);
        setTrail(res.data.trail);
      } catch (err) {
        console.error("Error fetching trail:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchTrail();
  }, [id]);

  useEffect(() => {
    if (!id) return;
    const fetchHomestays = async () => {
      setHomestaysLoading(true);
      try {
        const res = await axios.get(`${API}/api/homestays/public/trail/${id}`);
        setHomestays(res.data.homestays);
      } catch (err) {
        console.error("Error fetching homestays:", err);
      } finally {
        setHomestaysLoading(false);
      }
    };
    fetchHomestays();
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen bg-cream flex items-center justify-center">
        <Loader2 className="h-10 w-10 animate-spin text-gold" />
      </div>
    );
  }

  if (!trail) {
    return (
      <div className="min-h-screen bg-cream flex flex-col items-center justify-center gap-4">
        <Mountain className="h-16 w-16 text-gray-300" />
        <h2 className="text-2xl font-bold text-charcoal">Trail Not Found</h2>
        <Link to="/" className="text-gold hover:text-gold-dark font-semibold flex items-center gap-1">
          <ArrowLeft className="h-4 w-4" /> Back to Home
        </Link>
      </div>
    );
  }

  const primaryImage = trail.images?.find((img) => img.is_primary);
  const heroImage = primaryImage
    ? `${API}${primaryImage.image_path}`
    : "https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1200&q=80";

  const diff = difficultyColors[trail.difficulty_level] || difficultyColors["Moderate"];
  const diffDot = difficultyDot[trail.difficulty_level] || difficultyDot["Moderate"];

  return (
    <div className="min-h-screen bg-cream">
      <Header user={user} onLogoutClick={() => setShowLogoutModal(true)} />

      {/* ── Hero Banner ── */}
      <div className="relative h-[70vh] min-h-[560px] overflow-hidden">
        <img
          src={heroImage}
          alt={trail.trail_name}
          className="w-full h-full object-cover object-center"
        />
        <div
          className="absolute inset-0"
          style={{ background: "linear-gradient(to top, rgba(0,0,0,0.85) 0%, rgba(0,0,0,0.38) 42%, rgba(0,0,0,0.06) 72%, rgba(0,0,0,0) 100%)" }}
        />

        <Link
          to="/"
          className="absolute top-24 left-6 inline-flex items-center gap-2 px-4 py-2 bg-black/30 backdrop-blur-md rounded-xl text-white text-sm font-medium border border-white/20 hover:bg-black/50 transition"
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Trails
        </Link>

        <div className="absolute bottom-0 left-0 right-0 px-6 sm:px-10 pb-12">
          <div className="max-w-5xl mx-auto">
            <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold border mb-4 ${diff}`}>
              <span className={`w-1.5 h-1.5 rounded-full ${diffDot}`} />
              {trail.difficulty_level}
            </span>
            <h1 className="text-4xl sm:text-5xl lg:text-6xl font-extrabold text-white mb-5 font-heading leading-tight drop-shadow-sm">
              {trail.trail_name}
            </h1>
            <div className="flex flex-wrap items-center gap-x-6 gap-y-2">
              <span className="flex items-center gap-1.5 text-white/90 text-sm font-medium">
                <MapPin className="h-4 w-4 text-gold flex-shrink-0" />
                {trail.region}
              </span>
              <span className="flex items-center gap-1.5 text-white/80 text-sm">
                <Clock className="h-4 w-4 text-white/50 flex-shrink-0" />
                {trail.duration_days} {trail.duration_days === 1 ? "Day" : "Days"}
              </span>
              {trail.max_altitude && (
                <span className="flex items-center gap-1.5 text-white/80 text-sm">
                  <Mountain className="h-4 w-4 text-white/50 flex-shrink-0" />
                  {Number(trail.max_altitude).toLocaleString()} m altitude
                </span>
              )}
              {trail.images?.length > 0 && (
                <span className="flex items-center gap-1.5 text-white/60 text-sm">
                  <Camera className="h-4 w-4 flex-shrink-0" />
                  {trail.images.length} photo{trail.images.length !== 1 ? "s" : ""}
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* ── Photo Gallery ── */}
      {trail.images?.length > 0 && (
        <div className="max-w-5xl mx-auto px-4 sm:px-6 mt-10 mb-2">
          <div className="flex items-center justify-between mb-5">
            <div className="flex items-center gap-3">
              <div className="w-1 h-6 rounded-full" style={{ background: "linear-gradient(to bottom, #C8932A, #E0B04A)" }} />
              <h2 className="text-xl font-bold text-charcoal font-heading tracking-tight">Trail Gallery</h2>
              <span className="text-xs text-gray-400 font-medium bg-gray-100 px-2.5 py-1 rounded-full">
                {trail.images.length} photo{trail.images.length !== 1 ? "s" : ""}
              </span>
            </div>
            <p className="text-xs text-gray-400 hidden sm:block">Click any photo to enlarge</p>
          </div>
          <PhotoGallery images={trail.images} />
        </div>
      )}

      {/* ── Main Content ── */}
      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-12">
        <div className="grid lg:grid-cols-3 gap-10">

          {/* Left col: Description + Itinerary */}
          <div className="lg:col-span-2 space-y-12">

            {/* About */}
            <motion.div initial={{ opacity: 0, y: 24 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}>
              <div className="mb-5">
                <SectionHeading>About This Trek</SectionHeading>
              </div>
              <p className="text-gray-600 leading-[1.85] text-[15px] whitespace-pre-line">{trail.description}</p>

              {/* Quick facts */}
              <div className="mt-6 grid grid-cols-2 sm:grid-cols-3 gap-3">
                <div className="flex items-center gap-3 bg-white rounded-xl px-4 py-3 border border-gray-100 shadow-sm">
                  <div className="p-2 rounded-lg bg-gold/10">
                    <MapPin className="h-4 w-4 text-gold" />
                  </div>
                  <div>
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest font-semibold leading-none mb-0.5">Region</p>
                    <p className="text-sm font-semibold text-charcoal">{trail.region}</p>
                  </div>
                </div>
                <div className="flex items-center gap-3 bg-white rounded-xl px-4 py-3 border border-gray-100 shadow-sm">
                  <div className="p-2 rounded-lg bg-blue-50">
                    <Calendar className="h-4 w-4 text-blue-500" />
                  </div>
                  <div>
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest font-semibold leading-none mb-0.5">Duration</p>
                    <p className="text-sm font-semibold text-charcoal">{trail.duration_days} Days</p>
                  </div>
                </div>
                {trail.max_altitude && (
                  <div className="flex items-center gap-3 bg-white rounded-xl px-4 py-3 border border-gray-100 shadow-sm">
                    <div className="p-2 rounded-lg bg-violet-50">
                      <Mountain className="h-4 w-4 text-violet-500" />
                    </div>
                    <div>
                      <p className="text-[10px] text-gray-400 uppercase tracking-widest font-semibold leading-none mb-0.5">Max Altitude</p>
                      <p className="text-sm font-semibold text-charcoal">{Number(trail.max_altitude).toLocaleString()} m</p>
                    </div>
                  </div>
                )}
              </div>
            </motion.div>

            {/* Itinerary */}
            {trail.itineraries?.length > 0 && (
              <motion.div initial={{ opacity: 0, y: 24 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}>
                <div className="mb-8">
                  <SectionHeading>Day-by-Day Itinerary</SectionHeading>
                </div>

                <div className="relative">
                  <div className="absolute left-[19px] top-6 bottom-6 w-0.5 bg-gradient-to-b from-gold/60 via-gold/20 to-transparent" />
                  <div className="space-y-0">
                    {trail.itineraries.map((it, index) => (
                      <motion.div
                        key={it.itinerary_id}
                        initial={{ opacity: 0, x: -16 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ delay: 0.3 + index * 0.06 }}
                        className="flex gap-5 pb-6 last:pb-0"
                      >
                        <div className="relative flex-shrink-0 z-10">
                          <div
                            className="w-10 h-10 rounded-full flex items-center justify-center text-white text-xs font-extrabold shadow-md"
                            style={{ background: "linear-gradient(135deg, #C8932A, #E0B04A)" }}
                          >
                            {it.day_number}
                          </div>
                        </div>
                        <div className="flex-1 bg-white rounded-2xl px-5 py-4 border border-gray-100 shadow-sm hover:shadow-md transition-shadow mb-1">
                          <p className="text-[10px] text-gray-400 uppercase tracking-widest font-bold mb-1">Day {it.day_number}</p>
                          {it.title && <h3 className="text-base font-bold text-charcoal mb-2 leading-snug">{it.title}</h3>}
                          <p className="text-gray-500 text-sm leading-relaxed mb-3">{it.description}</p>
                          {(it.altitude || it.distance_km || it.walking_hours) && (
                            <div className="flex flex-wrap gap-4 pt-3 border-t border-gray-50">
                              {it.altitude && (
                                <span className="flex items-center gap-1.5 text-xs text-gray-400 font-medium">
                                  <Mountain className="h-3.5 w-3.5 text-gold" />
                                  {Number(it.altitude).toLocaleString()} m
                                </span>
                              )}
                              {it.distance_km && (
                                <span className="flex items-center gap-1.5 text-xs text-gray-400 font-medium">
                                  <Route className="h-3.5 w-3.5 text-blue-400" />
                                  {it.distance_km} km
                                </span>
                              )}
                              {it.walking_hours && (
                                <span className="flex items-center gap-1.5 text-xs text-gray-400 font-medium">
                                  <Timer className="h-3.5 w-3.5 text-violet-400" />
                                  {it.walking_hours} hrs
                                </span>
                              )}
                            </div>
                          )}
                        </div>
                      </motion.div>
                    ))}
                  </div>
                </div>
              </motion.div>
            )}
          </div>

          {/* Right col: Trek Details */}
          <motion.div
            initial={{ opacity: 0, y: 24 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="lg:col-span-1"
          >
            <div className="bg-white rounded-2xl border border-gray-100 shadow-lg overflow-hidden sticky top-28">
              <div className="px-6 py-5 border-b border-gray-100">
                <h3 className="text-base font-bold text-charcoal">Trek Details</h3>
                <p className="text-xs text-gray-400 mt-0.5">Key facts at a glance</p>
              </div>

              <div className="px-6 divide-y divide-gray-50">
                <div className="flex items-center justify-between py-3.5">
                  <span className="flex items-center gap-2 text-sm text-gray-500">
                    <MapPin className="h-4 w-4 text-gold" /> Region
                  </span>
                  <span className="text-sm font-semibold text-charcoal">{trail.region}</span>
                </div>
                <div className="flex items-center justify-between py-3.5">
                  <span className="flex items-center gap-2 text-sm text-gray-500">
                    <Calendar className="h-4 w-4 text-blue-400" /> Duration
                  </span>
                  <span className="text-sm font-semibold text-charcoal">{trail.duration_days} Days</span>
                </div>
                <div className="flex items-center justify-between py-3.5">
                  <span className="flex items-center gap-2 text-sm text-gray-500">
                    <TrendingUp className="h-4 w-4 text-orange-400" /> Difficulty
                  </span>
                  <span className={`text-xs font-bold px-3 py-1 rounded-full border ${diff}`}>
                    {trail.difficulty_level}
                  </span>
                </div>
                {trail.max_altitude && (
                  <div className="flex items-center justify-between py-3.5">
                    <span className="flex items-center gap-2 text-sm text-gray-500">
                      <Mountain className="h-4 w-4 text-violet-400" /> Max Altitude
                    </span>
                    <span className="text-sm font-semibold text-charcoal">
                      {Number(trail.max_altitude).toLocaleString()} m
                    </span>
                  </div>
                )}
                {trail.itineraries?.length > 0 && (
                  <div className="flex items-center justify-between py-3.5">
                    <span className="flex items-center gap-2 text-sm text-gray-500">
                      <Route className="h-4 w-4 text-emerald-400" /> Itinerary
                    </span>
                    <span className="text-sm font-semibold text-charcoal">
                      {trail.itineraries.length} {trail.itineraries.length === 1 ? "Day" : "Days"}
                    </span>
                  </div>
                )}
                {homestays.length > 0 && (
                  <div className="flex items-center justify-between py-3.5">
                    <span className="flex items-center gap-2 text-sm text-gray-500">
                      <Home className="h-4 w-4 text-amber-400" /> Homestays
                    </span>
                    <span className="text-sm font-semibold text-charcoal">{homestays.length} available</span>
                  </div>
                )}
              </div>

              {/* GPX download */}
              {trail.gpx_file_path && (
                <div className="px-6 pt-4 pb-2">
                  <a
                    href={`${API}${trail.gpx_file_path}`}
                    download
                    className="w-full flex items-center justify-center gap-2 py-3 text-sm font-semibold rounded-xl border-2 border-dashed border-gray-200 text-gray-500 hover:border-gold hover:text-gold transition-colors group"
                  >
                    <Download className="h-4 w-4 group-hover:animate-bounce" />
                    Download GPX File
                  </a>
                </div>
              )}

              <div className="px-6 pb-6 pt-3">
                <p className="text-[11px] text-center text-gray-400 leading-relaxed">
                  GPX file compatible with Garmin, Caltopo, AllTrails &amp; more
                </p>
              </div>
            </div>
          </motion.div>
        </div>

        {/* ── Homestays Section ── */}
        <motion.div
          initial={{ opacity: 0, y: 24 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4 }}
          className="mt-14"
        >
          <div className="flex items-center justify-between mb-6">
            <SectionHeading>
              Where to Stay
              {!homestaysLoading && homestays.length > 0 && (
                <span className="ml-2 text-sm font-normal text-gray-400">
                  — {homestays.length} homestay{homestays.length !== 1 ? "s" : ""} on this trail
                </span>
              )}
            </SectionHeading>
          </div>

          {homestaysLoading ? (
            <div className="flex items-center justify-center py-16">
              <Loader2 className="h-7 w-7 animate-spin text-gold" />
            </div>
          ) : homestays.length === 0 ? (
            <div className="flex flex-col items-center py-14 gap-3 bg-white rounded-2xl border border-gray-100">
              <Home className="h-12 w-12 text-gray-200" />
              <p className="text-gray-500 font-semibold">No homestays listed yet</p>
              <p className="text-gray-400 text-sm text-center max-w-xs">
                Homestays for this trail will appear here once hosts list them and they're approved.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
              {homestays.map((h, i) => (
                <HomestayCard key={h.homestay_id} homestay={h} />
              ))}
            </div>
          )}
        </motion.div>
      </div>

      <Footer />

      <LogoutModal
        isOpen={showLogoutModal}
        onConfirm={handleLogout}
        onCancel={handleStayLoggedIn}
      />
    </div>
  );
};

export default TrailDetail;
